def run_agent(messages: list, budget: int) -> str:
    spent = 0
    while spent < budget:
        reply = llm(messages)
        spent += reply.tokens
        if not reply.tool_calls:
            return reply.text
        for call in reply.tool_calls:
            messages.append(execute_tool(call))
    return "Budget exhausted"

